#include <stdio.h>
#include <stdlib.h>
#include <string.h>

#define MAXROWS 300
#define MAXCOLS 300

char grid[MAXROWS][MAXCOLS+1];
int rows, cols;

// Find start position
int start_col;

// For part 1: count total number of split events
// A beam moves downward. When it hits a ^, it splits into left and right beams.
// We need to track which beams have been processed to avoid infinite loops.
// But beams can revisit splitters if multiple beams pass through the same point.
// Actually - can a beam revisit? Beams always move downward and spawn new downward beams.
// A beam at column c, row r moves down. It can only hit a splitter below it.
// So the beam path is strictly increasing in row - no cycles possible.
// But multiple beams can hit the same splitter.

// Actually, let's think about it differently:
// Each "beam" is defined by its starting column and the row it starts from.
// When a beam hits a splitter at (row, col), it spawns beams at (row, col-1) and (row, col+1)
// starting from row+1 (actually starting from row, going downward, first step to row+1).
// Wait - "a new tachyon beam continues from the immediate left and from the immediate right of the splitter"
// So the new beams start at (splitter_row, col-1) and (splitter_row, col+1) and move downward.

// State: (start_row, start_col) for each beam
// We process beams via BFS/DFS

// For part 1, we need to count UNIQUE splitter hits (or total hits?)
// The problem says "split a total of 21 times" for the example.
// Looking at the grid: there are splitters, and beams hit them.
// Multiple beams can hit the same splitter (that counts as multiple splits).
// But we need to avoid infinite processing - can the same beam state repeat?
// 
// A beam starts at (row, col) and moves downward. If two beams start at the same (row, col),
// they'd produce identical results. So we deduplicate beam starting positions.

// Let's use a set of visited (start_row, start_col) pairs.

typedef struct {
    int row, col;
} Beam;

// Queue for BFS
Beam queue[MAXROWS * MAXCOLS * 4];
int qhead, qtail;

// Visited set: visited[row][col] = 1 if we've processed a beam starting here
int visited[MAXROWS][MAXCOLS];

long long part1_splits;
long long part2_timelines;

// Simulate: for each beam starting at (start_row, start_col) moving downward,
// find the first splitter it hits.
// Returns: row of splitter hit, or -1 if exits grid.
// Also: col stays the same as start_col.

void simulate(int do_part2) {
    // Reset
    memset(visited, 0, sizeof(visited));
    part1_splits = 0;
    part2_timelines = 0;

    qhead = qtail = 0;

    // Start beam from row 0, start_col, moving down
    // Actually the beam starts from S which is at row 0.
    // The beam starts just below S (row 1? or at S row moving down?)
    // S is the entry point - beam enters moving down.
    // Let's say beam starts at row=0, col=start_col (at S position itself, moving down)

    // Find S
    int s_row = -1, s_col = -1;
    for (int r = 0; r < rows; r++) {
        for (int c = 0; c < cols; c++) {
            if (grid[r][c] == 'S') {
                s_row = r; s_col = c;
            }
        }
    }

    queue[qtail++] = (Beam){s_row, s_col};
    visited[s_row][s_col] = 1;

    while (qhead < qtail) {
        Beam b = queue[qhead++];
        int r = b.row, c = b.col;

        // Move downward from (r, c) - find first ^ below (or at current if already at ^?)
        // The beam starts at (r,c) - if S is there, it moves down.
        // If spawned by a splitter at (sr, sc), it starts at (sr, sc±1) and moves down.
        // Find the first ^ at or below current position in column c

        int hit = -1;
        for (int nr = r; nr < rows; nr++) {
            if (grid[nr][c] == '^') {
                hit = nr;
                break;
            }
        }

        if (hit == -1) {
            // Beam exits grid - no split
            if (do_part2) part2_timelines++;
        } else {
            // Beam hits splitter at (hit, c)
            part1_splits++;

            // Spawn left beam at (hit, c-1) and right beam at (hit, c+1)
            // But only if they're in bounds
            int left_c = c - 1;
            int right_c = c + 1;

            if (do_part2) {
                // In many-worlds: we count timelines
                // Each split creates 2 sub-timelines
                // We'll handle this differently for part 2
            }

            // Left beam
            if (left_c >= 0) {
                if (!visited[hit][left_c]) {
                    visited[hit][left_c] = 1;
                    queue[qtail++] = (Beam){hit, left_c};
                } else {
                    // This beam was already processed - but it could still split again
                    // Actually if we've processed it before, we'd double-count
                    // Hmm, but for part 1, we want TOTAL splits including from same position
                    // Wait - can the same beam position appear multiple times?
                    // A beam at (hit, left_c) is spawned - if another beam also spawns at (hit, left_c),
                    // they'd produce the same downstream splits. For part 1, do we count them separately?
                }
            }

            // Right beam
            if (right_c < cols) {
                if (!visited[hit][right_c]) {
                    visited[hit][right_c] = 1;
                    queue[qtail++] = (Beam){hit, right_c};
                }
            }
        }
    }
}

int main(int argc, char *argv[]) {
    int part = 0;
    if (argc > 1) part = atoi(argv[1]);

    FILE *f = fopen("input.txt", "r");
    if (!f) { fprintf(stderr, "Cannot open input.txt\n"); return 1; }

    rows = 0;
    while (fgets(grid[rows], MAXCOLS+1, f)) {
        // Remove newline
        int len = strlen(grid[rows]);
        while (len > 0 && (grid[rows][len-1] == '\n' || grid[rows][len-1] == '\r'))
            grid[rows][--len] = '\0';
        if (len > 0) {
            cols = len;
            rows++;
        }
    }
    fclose(f);

    simulate(0);
    long long ans1 = part1_splits;

    // For part 2, need different approach
    // Part 2: count timelines = 2^(splits on path)?
    // Actually, let me think recursively:
    // timelines(beam_at(r,c)) = 
    //   if no splitter below: 1 (exits, 1 timeline)
    //   if splitter at (h,c): timelines(h, c-1) + timelines(h, c+1)
    //     (if one side is out of bounds, it contributes 0? or 1?)
    //     Hmm, if left is out of bounds, beam exits immediately = 1 timeline
    //     
    // Actually when a beam spawns at (h, c-1) and c-1 < 0, it immediately exits = 1 timeline
    // When it spawns at (h, c-1) and c-1 >= 0, it continues
    //
    // But we need memoization to avoid exponential blowup.
    // memo[r][c] = number of timelines for beam starting at (r,c)

    // Let's implement that with memoization

    if (part == 0 || part == 1) {
        printf("Part 1: %lld\n", ans1);
    }

    if (part == 0 || part == 2) {
        // Part 2: memoized recursion
        // But wait - is memoization valid? Can two beams starting at same (r,c) give same result?
        // Yes! The beam's future depends only on where it starts. So memoize.

        // memo[r][c] = timelines for beam starting at (r, c) going down
        long long memo[MAXROWS][MAXCOLS];
        memset(memo, -1, sizeof(memo));

        // Find S
        int s_row = -1, s_col = -1;
        for (int r = 0; r < rows; r++) {
            for (int c = 0; c < cols; c++) {
                if (grid[r][c] == 'S') {
                    s_row = r; s_col = c;
                }
            }
        }

        // Recursive function - use iterative with stack to avoid stack overflow
        // Actually, let's do it bottom-up:
        // Process from bottom row to top
        // For each cell (r, c), compute timelines if a beam starts there going down

        // A beam at (r, c) scans down from r to find first ^
        // Then timelines(r, c) = timelines(hit, c-1) + timelines(hit, c+1)
        // where timelines of out-of-bounds = 1 (beam exits immediately = 1 path)
        // If no splitter found: timelines = 1 (beam exits at bottom = 1 path)

        // We need to precompute for each (r, c): where is the next ^ below (inclusive)
        // next_splitter[r][c] = row of next ^ at column c at or below row r, -1 if none
        int next_split[MAXROWS][MAXCOLS];
        for (int c = 0; c < cols; c++) {
            next_split[rows][c] = -1; // sentinel
            for (int r = rows-1; r >= 0; r--) {
                if (grid[r][c] == '^') {
                    next_split[r][c] = r;
                } else {
                    next_split[r][c] = next_split[r+1][c];
                }
            }
        }

        // Now compute memo bottom-up
        // We need to process in order where dependencies are already computed.
        // timelines(r, c) depends on timelines(hit, c-1) and timelines(hit, c+1)
        // where hit = next_split[r][c] >= r
        // The dependencies have the SAME row as the hit, which could be any row.
        // But timelines(hit, c±1) depends on next_split[hit][c±1] which is >= hit.
        // So dependencies are at >= hit >= r.
        // Wait: timelines(hit, c-1) - the beam starts at (hit, c-1) and goes down.
        // Its first splitter is next_split[hit][c-1], which is >= hit.
        // 
        // So the dependencies can be at the same row or below.
        // If at the same row: could be circular? No, because c changes.
        // 
        // Actually there could be cycles if beams could go left/right and then down again
        // hitting the same column. But beams only go DOWN. So no cycles.
        // 
        // But bottom-up: process from bottom-right? 
        // Actually the dependencies are at same or deeper rows but DIFFERENT columns.
        // Let's just do memoized recursion with explicit stack.

        // Use iterative DFS with memo
        typedef struct { int r, c, phase; } Frame;
        Frame stack[MAXROWS * MAXCOLS * 2];
        int top = 0;

        memset(memo, 0, sizeof(memo)); // init to 0, use -1 as "not computed"
        // Actually let's use a separate "computed" array
        char computed[MAXROWS][MAXCOLS];
        memset(computed, 0, sizeof(computed));

        // Reset memo to -1 using long long
        for (int r = 0; r < rows; r++)
            for (int c = 0; c < cols; c++)
                memo[r][c] = -1;

        stack[top++] = (Frame){s_row, s_col, 0};

        while (top > 0) {
            Frame *fr = &stack[top-1];
            int r = fr->r, c = fr->c;

            if (computed[r][c]) {
                top--;
                continue;
            }

            int hit = next_split[r][c];

            if (hit == -1) {
                // No splitter, beam exits
                memo[r][c] = 1;
                computed[r][c] = 1;
                top--;
                continue;
            }

            // Need timelines for (hit, c-1) and (hit, c+1)
            int lc = c - 1, rc2 = c + 1;
            long long left_t = 1, right_t = 1; // default: exits immediately

            int need_left = 0, need_right = 0;
            if (lc >= 0 && !computed[hit][lc]) need_left = 1;
            if (rc2 < cols && !computed[hit][rc2]) need_right = 1;

            if (need_left || need_right) {
                if (fr->phase == 0) {
                    fr->phase = 1;
                    if (need_right) stack[top++] = (Frame){hit, rc2, 0};
                    if (need_left) stack[top++] = (Frame){hit, lc, 0};
                    continue;
                }
            }

            // All dependencies computed
            if (lc >= 0) left_t = memo[hit][lc];
            if (rc2 < cols) right_t = memo[hit][rc2];

            memo[r][c] = left_t + right_t;
            computed[r][c] = 1;
            top--;
        }

        printf("Part 2: %lld\n", memo[s_row][s_col]);
    }

    return 0;
}

