long long simulate_part1(int s_row, int s_col) {
    memset(splitter_hit, 0, sizeof(splitter_hit));
    memset(visited, 0, sizeof(visited));
    qhead = qtail = 0;

    queue[qtail++] = (Beam){s_row, s_col};
    visited[s_row][s_col] = 1;

    long long splits = 0;

    while (qhead < qtail) {
        Beam b = queue[qhead++];
        int r = b.row, c = b.col;

        int hit = next_split[r][c];

        if (hit < 0) {
